use std::collections::{HashMap, BTreeSet};

struct UnionFind {
    parent: Vec<i64>,
}

impl UnionFind {
    fn new(size: usize) -> Self {
        UnionFind {
            parent: (0..size as i64).collect(),
        }
    }

    fn find(&mut self, x: i64) -> i64 {
        let x = x as usize;
        if self.parent[x] != x as i64 {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: i64, y: i64) {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x != root_y {
            self.parent[root_y as usize] = root_x;
        }
    }
}

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    let mut uf = UnionFind::new(c + 1); // 1-based indexing
    for conn in connections {
        let u = conn[0];
        let v = conn[1];
        uf.union(u, v);
    }

    let mut online = vec![true; c + 1];
    let mut component_min: HashMap<i64, BTreeSet<i64>> = HashMap::new();

    for i in 1..=c as i64 {
        let root = uf.find(i);
        component_min.entry(root).or_default().insert(i);
    }

    let mut result = Vec::new();
    for query in queries {
        let query_type = query[0];
        let x = query[1];
        if query_type == 1 {
            let root = uf.find(x);
            let mut answer = -1;
            if let Some(set) = component_min.get(&root) {
                for &node in set {
                    if online[node as usize] {
                        answer = node;
                        break;
                    }
                }
            }
            result.push(answer);
        } else if query_type == 2 {
            online[x as usize] = false;
        }
    }
    result
}
