use std::collections::{HashMap, BTreeSet};

struct UnionFind {
    parent: Vec<i64>,
}

impl UnionFind {
    fn new(size: usize) -> Self {
        UnionFind {
            parent: (0..size as i64).collect(),
        }
    }

    fn find(&mut self, x: i64) -> i64 {
        if self.parent[x as usize] != x {
            self.parent[x as usize] = self.find(self.parent[x as usize]);
        }
        self.parent[x as usize]
    }

    fn union(&mut self, x: i64, y: i64) {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x != root_y {
            self.parent[root_y as usize] = root_x;
        }
    }
}

pub fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut uf = UnionFind::new((c + 1) as usize);
    for conn in connections {
        uf.union(conn[0], conn[1]);
    }

    let mut online = vec![true; (c + 1) as usize];
    let mut component_min: HashMap<i64, BTreeSet<i64>> = HashMap::new();

    for i in 1..=c {
        let root = uf.find(i);
        component_min.entry(root).or_default().insert(i);
    }

    let mut result = Vec::new();
    for query in queries {
        let query_type = query[0];
        let x = query[1];
        if query_type == 1 {
            let root = uf.find(x);
            let answer = component_min.get(&root)
                .and_then(|set| set.iter().find(|&&node| online[node as usize]).copied())
                .unwrap_or(-1);
            result.push(answer);
        } else if query_type == 2 {
            online[x as usize] = false;
        }
    }
    result
}
