function solve(c, connections, queries) {
    // Initialize Union-Find to manage the connected components
    const uf = new UnionFind(c + 1); // 1-based indexing
    for (const [u, v] of connections) {
        uf.union(u, v);
    }

    // Track online status: true means online, false means offline
    const online = new Array(c + 1).fill(true);

    // For each component, maintain a min-heap of online nodes
    const componentMin = new Map();
    for (let i = 1; i <= c; i++) {
        const root = uf.find(i);
        if (!componentMin.has(root)) {
            componentMin.set(root, new Set());
        }
        componentMin.get(root).add(i);
    }

    // Convert the sets to sorted arrays for efficient min lookup
    const componentMinSorted = new Map();
    for (const [root, nodes] of componentMin) {
        componentMinSorted.set(root, Array.from(nodes).sort((a, b) => a - b));
    }

    const result = [];
    for (const [type, x] of queries) {
        if (type === 1) {
            const root = uf.find(x);
            const sortedNodes = componentMinSorted.get(root);
            let answer = -1;
            // Find the first online node in the sorted list
            for (const node of sortedNodes) {
                if (online[node]) {
                    answer = node;
                    break;
                }
            }
            result.push(answer);
        } else if (type === 2) {
            online[x] = false;
        }
    }
    return result;
}

