            for (const node of sortedNodes) {
                if (online[node]) {
                    answer = node;
                    break;
                }
            }
            result.push(answer);
        } else if (type === 2) {
            online[x] = false;
        }
    }
    return result;
}

// Since JavaScript doesn't have a built-in UnionFind, we need to implement it
class UnionFind {
    constructor(size) {
        this.parent = new Array(size);
        for (let i = 0; i < size; i++) {
            this.parent[i] = i;
        }
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const rootX = this.find(x);
        const rootY = this.find(y);
        if (rootX !== rootY) {
            this.parent[rootY] = rootX;
        }
    }
}
